package com.jian.nemo.core.domain.usecase.word

import com.jian.nemo.core.common.Result
import com.jian.nemo.core.domain.model.Word
import com.jian.nemo.core.domain.repository.WordRepository
import javax.inject.Inject

/**
 * 更新单词 
 * 用于 SRS 算法更新单词状态 (Interval, EasinessFactor, etc.)
 */
class UpdateWordUseCase @Inject constructor(
    private val wordRepository: WordRepository
) {
    suspend operator fun invoke(word: Word): Result<Unit> {
        return try {
            // 🎯 补齐时间戳逻辑
            val updatedWord = word.copy(lastModifiedTime = com.jian.nemo.core.common.util.DateTimeUtils.getCurrentCompensatedMillis())
            wordRepository.updateWord(updatedWord)
        } catch (e: Exception) {
            Result.Error(e)
        }
    }
}
